from flask import Flask, request, redirect, session
import requests

app = Flask(__name__)
app.secret_key = 'super secret key'  # replace with your own secret key

# you should set these in a secure manner that is not in the codebase for security reasons
client_id = 'your-client-id'
client_secret = 'your-client-secret'
authorization_url = 'https://auth.server/authorize'  # replace with your authorization server url
token_url = 'https://auth.server/token'  # replace with your token exchange url
redirect_uri = 'http://localhost:5000/callback'  # this should match the callback endpoint in your app settings on the auth server
scope = 'openid email profile'

@app.route("/")
def index():
    return "OAuth 2.0 Client"

@app.route('/login')
def login():
    redirect_uri = f"{authorization_url}?response_type=code&client_id={client_id}&redirect_uri={redirect_uri}&scope={scope}"
    return redirect(redirect_uri, code=302)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    
    token_response = requests.post(token_url, data={
        'grant_type': 'authorization_code',
        'client_id': client_id,
        'client_secret': client_secret,
        'redirect_uri': redirect_uri,
        'code': code
    })
    
    token_data = token_response.json()
    session['access_token'] = token_data['access_token']  # replace 'access_token' with the actual key your auth server returns
    
    return redirect('/')